// Pega a resposta do nó anterior (independente de qual nó HTTP veio)
let rawResponse = $input.first().json.response;

try {
  if (!rawResponse) throw new Error("A resposta da IA veio vazia");

  // 1. Limpa sujeiras comuns de IA (markdown, tags e espaços)
  let cleanData = rawResponse
    .replace(/```json|```/g, "")
    .replace(/<[^>]*>/g, "")
    .trim();

  // 2. CONVERSÃO CHAVE: Transforma a string em um objeto JSON de verdade
  const parsed = JSON.parse(cleanData);

  // 3. Retorna o JSON estruturado para o seu backend
  return parsed;

} catch (e) {
  // Se a IA não retornar um JSON válido, enviamos o texto como 'conteudo' para não perder a informação
  return {
    campo: "Erro de Formatação",
    conteudo: rawResponse,
    erro_debug: e.message
  };
}

